import React, { useEffect, useRef } from 'react';

/* ── Animated water canvas + one large Rohu fish image ── */
export default function FishBackground() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let animId;

    const resize = () => {
      canvas.width  = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    resize();
    window.addEventListener('resize', resize);

    /* ── Caustic light blobs ── */
    const caustics = Array.from({ length: 22 }, () => ({
      x:      Math.random() * window.innerWidth,
      y:      Math.random() * window.innerHeight,
      rx:     40 + Math.random() * 100,
      ry:     18 + Math.random() * 55,
      rot:    Math.random() * Math.PI,
      phase:  Math.random() * Math.PI * 2,
      speed:  0.006 + Math.random() * 0.01,
    }));

    /* ── Rising bubbles ── */
    const bubbles = Array.from({ length: 18 }, () => mkBubble());
    function mkBubble() {
      return {
        x:      Math.random() * window.innerWidth,
        y:      window.innerHeight + 20,
        r:      2 + Math.random() * 6,
        speed:  0.35 + Math.random() * 0.7,
        wobble: Math.random() * Math.PI * 2,
        wSpeed: 0.02 + Math.random() * 0.03,
        alpha:  0.15 + Math.random() * 0.35,
      };
    }

    /* ── Light rays from surface ── */
    const rays = Array.from({ length: 8 }, () => ({
      x:      Math.random() * window.innerWidth,
      width:  30 + Math.random() * 60,
      phase:  Math.random() * Math.PI * 2,
      speed:  0.005 + Math.random() * 0.008,
      alpha:  0.03 + Math.random() * 0.05,
    }));

    /* ── Horizontal wave lines ── */
    const waveLines = Array.from({ length: 6 }, (_, i) => ({
      y:      (i + 1) * (window.innerHeight / 7),
      phase:  Math.random() * Math.PI * 2,
      speed:  0.007 + Math.random() * 0.008,
      amp:    8 + Math.random() * 14,
    }));

    let t = 0;

    function drawWater() {
      /* deep water gradient */
      const g = ctx.createLinearGradient(0, 0, 0, canvas.height);
      g.addColorStop(0,   'rgb(8,  60, 120)');
      g.addColorStop(0.4, 'rgb(6,  40,  90)');
      g.addColorStop(1,   'rgb(2,  18,  45)');
      ctx.fillStyle = g;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
    }

    function drawRays() {
      rays.forEach(r => {
        r.phase += r.speed;
        const alpha = r.alpha * (0.6 + 0.4 * Math.sin(r.phase));
        ctx.save();
        const rg = ctx.createLinearGradient(r.x, 0, r.x, canvas.height * 0.85);
        rg.addColorStop(0,   `rgba(180,230,255,${alpha})`);
        rg.addColorStop(1,   'rgba(180,230,255,0)');
        ctx.beginPath();
        ctx.moveTo(r.x - r.width / 2, 0);
        ctx.lineTo(r.x + r.width / 2, 0);
        ctx.lineTo(r.x + r.width * 1.8, canvas.height * 0.85);
        ctx.lineTo(r.x - r.width * 1.8, canvas.height * 0.85);
        ctx.closePath();
        ctx.fillStyle = rg;
        ctx.fill();
        ctx.restore();
      });
    }

    function drawCaustics() {
      caustics.forEach(c => {
        c.phase += c.speed;
        const s     = 0.55 + 0.45 * Math.abs(Math.sin(c.phase));
        const alpha = 0.025 + 0.04 * Math.abs(Math.sin(c.phase * 0.7));
        ctx.save();
        ctx.globalAlpha = alpha;
        ctx.translate(c.x, c.y);
        ctx.rotate(c.rot + c.phase * 0.3);
        ctx.beginPath();
        ctx.ellipse(0, 0, c.rx * s, c.ry * s, 0, 0, Math.PI * 2);
        ctx.strokeStyle = 'rgba(180,230,255,0.9)';
        ctx.lineWidth = 1.5;
        ctx.stroke();
        ctx.restore();
      });
    }

    function drawWaveLines() {
      waveLines.forEach(wl => {
        wl.phase += wl.speed;
        ctx.save();
        ctx.globalAlpha = 0.07;
        ctx.beginPath();
        ctx.moveTo(0, wl.y);
        for (let x = 0; x <= canvas.width; x += 6) {
          ctx.lineTo(x, wl.y + Math.sin(x * 0.01 + wl.phase) * wl.amp);
        }
        ctx.strokeStyle = 'rgba(160,220,255,1)';
        ctx.lineWidth = 1.2;
        ctx.stroke();
        ctx.restore();
      });
    }

    function drawBubbles() {
      bubbles.forEach((b, i) => {
        b.wobble += b.wSpeed;
        b.y      -= b.speed;
        b.x      += Math.sin(b.wobble) * 0.5;
        if (b.y < -20) bubbles[i] = mkBubble();

        ctx.save();
        ctx.globalAlpha = b.alpha;
        ctx.beginPath();
        ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
        ctx.strokeStyle = 'rgba(200,240,255,0.9)';
        ctx.lineWidth = 1;
        ctx.stroke();
        /* shine */
        ctx.globalAlpha = b.alpha * 1.4;
        ctx.beginPath();
        ctx.arc(b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.28, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.85)';
        ctx.fill();
        ctx.restore();
      });
    }

    /* surface shimmer */
    const surfaceOffset = [0, 0];
    function drawSurface() {
      surfaceOffset[0] += 0.014;
      surfaceOffset[1] += 0.009;
      for (let layer = 0; layer < 2; layer++) {
        ctx.save();
        ctx.globalAlpha = 0.09 - layer * 0.03;
        ctx.beginPath();
        const yBase = 30 + layer * 25;
        ctx.moveTo(0, yBase);
        for (let x = 0; x <= canvas.width; x += 6) {
          ctx.lineTo(x, yBase + Math.sin(x * 0.009 + surfaceOffset[layer]) * (14 + layer * 6));
        }
        ctx.lineTo(canvas.width, 0);
        ctx.lineTo(0, 0);
        ctx.closePath();
        ctx.fillStyle = 'rgba(180,230,255,1)';
        ctx.fill();
        ctx.restore();
      }
    }

    function animate() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      t++;
      drawWater();
      drawRays();
      drawCaustics();
      drawWaveLines();
      drawBubbles();
      drawSurface();
      animId = requestAnimationFrame(animate);
    }

    animate();
    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener('resize', resize);
    };
  }, []);

  return (
    <>
      {/* Animated water canvas */}
      <canvas
        ref={canvasRef}
        style={{
          position:      'fixed',
          top:           0,
          left:          0,
          width:         '100vw',
          height:        '100vh',
          zIndex:        -2,
          pointerEvents: 'none',
          display:       'block',
        }}
      />

      {/* Single high-quality Rohu fish image */}
      <div style={{
        position:      'fixed',
        top:           0,
        left:          0,
        width:         '100vw',
        height:        '100vh',
        zIndex:        -1,
        pointerEvents: 'none',
        overflow:      'hidden',
      }}>
        <img
          src="https://images.unsplash.com/photo-1524704654690-b56c05c78a02?auto=format&fit=crop&w=3840&q=100"
          alt="Rohu Fish"
          style={{
            position:        'absolute',
            /* start right, vertically centred */
            top:             '50%',
            left:            '60%',
            transform:       'translateY(-50%)',
            width:           '520px',
            maxWidth:        '55vw',
            objectFit:       'contain',
            filter:          'drop-shadow(0 0 32px rgba(0,180,255,0.55)) drop-shadow(0 0 8px rgba(0,0,0,0.6)) brightness(1.08) contrast(1.1)',
            animation:       'rohuSwim 9s ease-in-out infinite',
            imageRendering:  'high-quality',
          }}
        />
      </div>

      {/* CSS keyframe for the fish swimming */}
      <style>{`
        @keyframes rohuSwim {
          0%   { transform: translateY(-50%) translateX(0px)   scaleX(1); }
          20%  { transform: translateY(-54%) translateX(-22px) scaleX(1); }
          40%  { transform: translateY(-46%) translateX(-44px) scaleX(1); }
          50%  { transform: translateY(-50%) translateX(-55px) scaleX(-1); }
          70%  { transform: translateY(-55%) translateX(-28px) scaleX(-1); }
          80%  { transform: translateY(-45%) translateX(-10px) scaleX(-1); }
          99%  { transform: translateY(-50%) translateX(0px)   scaleX(-1); }
          100% { transform: translateY(-50%) translateX(0px)   scaleX(1); }
        }
      `}</style>
    </>
  );
}
